type TigrisResponse<T, E = Error> = {
    data: T;
    error?: never;
} | {
    error: E;
    data?: never;
};
type TigrisEndpointsConfig = {
    endpoint?: string;
    iamEndpoint?: string;
    mgmtEndpoint?: string;
};
type TigrisAuthConfig = {
    accessKeyId?: string;
    secretAccessKey?: string;
    sessionToken?: string;
    organizationId?: string;
    credentialProvider?: () => Promise<{
        accessKeyId: string;
        secretAccessKey: string;
        sessionToken?: string;
        expiration?: Date;
    }>;
};
type TigrisConfig = TigrisEndpointsConfig & TigrisAuthConfig;

/**
 * Unified configuration for Tigris Agentic operations.
 * Accepted directly by both `@tigrisdata/storage` and `@tigrisdata/iam`.
 * When omitted, the underlying SDKs fall back to environment variables.
 */
type TigrisAgentKitConfig = TigrisConfig;

type CheckpointOptions = {
    /** Optional name for the checkpoint snapshot. */
    name?: string;
    config?: TigrisAgentKitConfig;
};
type Checkpoint = {
    snapshotId: string;
    name?: string;
    createdAt?: Date;
};
type RestoreOptions = {
    /** Name for the restored fork bucket. Defaults to `${bucket}-restore-${timestamp}`. */
    forkName?: string;
    config?: TigrisAgentKitConfig;
};
type RestoreResult = {
    bucket: string;
};
type ListCheckpointsOptions = {
    limit?: number;
    paginationToken?: string;
    config?: TigrisAgentKitConfig;
};
type ListCheckpointsResponse = {
    checkpoints: Checkpoint[];
    paginationToken?: string;
};
