import { Sha256 } from "@aws-crypto/sha256-js";
import { SignatureV4 } from "@smithy/signature-v4";

async function signedRequest(method, url, body, headers = {}) {
  const parsedUrl = new URL(url);
  const signer = new SignatureV4({
    credentials: { accessKeyId, secretAccessKey },
    region: "REDACTED",
    service: "s3",
    sha256: Sha256,
    uriEscapePath: false,
  });

  const bodyStr = body ? JSON.stringify(body) : undefined;
  const query = {};
  parsedUrl.searchParams.forEach((v, k) => { query[k] = v; });

  const signed = await signer.sign({
    method,
    protocol: parsedUrl.protocol,
    hostname: parsedUrl.hostname,
    port: parsedUrl.port ? parseInt(parsedUrl.port, 10) : undefined,
    path: parsedUrl.pathname,
    ...(Object.keys(query).length > 0 && { query }),
    headers: {
      "Content-Type": "application/json",
      ...headers,
      host: parsedUrl.host,
    },
    body: bodyStr,
  });

  const fetchOpts = { method, headers: signed.headers };
  if (bodyStr) fetchOpts.body = bodyStr;

  const resp = await fetch(url, fetchOpts);
  const text = await resp.text();
  console.log(`  ${method} ${parsedUrl.pathname} => ${resp.status} ${resp.statusText}`);
  if (text) {
    try { console.log("  Response:", JSON.stringify(JSON.parse(text), null, 2)); }
    catch { console.log("  Response text:", text); }
  }
  return { status: resp.status, text };
}

for (const bucket of buckets) {
  console.log(`\nEnabling snapshots on ${bucket}...`);
  // Try PATCH with type=1 (snapshot type)
  await signedRequest("PATCH", `${endpoint}/${bucket}`, { type: 1 });
}

