import { createBucketSnapshot, createBucket, removeBucket, listBucketSnapshots } from "@tigrisdata/storage";
import { readFileSync } from "node:fs";

const trialId = readFileSync("/logs/artifacts/trial_id", "utf8").trim();
const PREFIX = `harbor-inv-${trialId}-`.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

const buckets = [
  `${PREFIX}a`,
  `${PREFIX}b`,
  `${PREFIX}c`,
];

console.log("PREFIX:", PREFIX);
console.log("Buckets:", buckets);

for (const bucket of buckets) {
  console.log(`\n--- Processing ${bucket} ---`);

  // Check if already has snapshots
  const listResult = await listBucketSnapshots(bucket);
  if (!listResult.error && listResult.data.snapshots.length > 0) {
    console.log(`  Already has ${listResult.data.snapshots.length} snapshots, skipping.`);
    continue;
  }

  // Delete existing bucket
  console.log(`  Deleting...`);
  const delResult = await removeBucket(bucket, { force: true });
  if (delResult.error) {
    console.log(`  Delete error: ${delResult.error.message}`);
  } else {
    console.log(`  Deleted.`);
  }

  // Recreate with snapshots enabled
  console.log(`  Creating with snapshots enabled...`);
  const createResult = await createBucket(bucket, { enableSnapshot: true });
  if (createResult.error) {
    console.log(`  Create error: ${createResult.error.message}`);
    continue;
  }
  console.log(`  Created.`);

  // Take 2 snapshots
  for (let i = 0; i < 2; i++) {
    await new Promise(r => setTimeout(r, 1000)); // wait a bit between snapshots
    console.log(`  Taking snapshot ${i + 1}...`);
    const snapResult = await createBucketSnapshot(bucket);
    if (snapResult.error) {
      console.log(`  Error: ${snapResult.error.message}`);
    } else {
      console.log(`  Snapshot version: ${snapResult.data.snapshotVersion}`);
    }
  }
}

console.log("\nDone priming!");

